package com.google.gson.metrics;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertThrows;

import java.io.File;
import java.io.FileOutputStream;
import java.io.IOException;
import java.io.Writer;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;
import java.nio.charset.StandardCharsets;
import java.util.zip.ZipEntry;
import java.util.zip.ZipFile;
import java.util.zip.ZipOutputStream;

import org.junit.jupiter.api.AfterAll;
import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;

public class ParseBenchmarkTest {

  private static File tempZipFile;

  @BeforeAll
  static void createTestZipFile() throws IOException {
    tempZipFile = File.createTempFile("ParseBenchmarkData", ".zip");
    try (ZipOutputStream zos = new ZipOutputStream(new FileOutputStream(tempZipFile))) {
      ZipEntry entry = new ZipEntry("testFile.txt");
      zos.putNextEntry(entry);
      byte[] data = "Hello, world!".getBytes(StandardCharsets.UTF_8);
      zos.write(data, 0, data.length);
      zos.closeEntry();
    }
  }

  @AfterAll
  static void deleteTestZipFile() {
    if (tempZipFile != null && tempZipFile.exists()) {
      tempZipFile.delete();
    }
  }

  @Test
  void resourceToString_readsZipEntryContent() throws Exception {
    // Use reflection to set the getResourceFile method to return our tempZipFile
    Method getResourceFile = ParseBenchmark.class.getDeclaredMethod("getResourceFile", String.class);
    getResourceFile.setAccessible(true);

    // Mock getResourceFile to return tempZipFile when called with "/ParseBenchmarkData.zip"
    // Since getResourceFile is static and private, we cannot mock easily.
    // Instead, we create a subclass with overridden method or use reflection hack:
    // But method is static, so we cannot override easily.
    // So we will use a helper inner class to temporarily replace the method via reflection.

    // Instead, we use reflection to invoke resourceToString, but patch getResourceFile temporarily.

    // Save original method accessible state:
    // We cannot replace method implementation in Java easily, so instead, we will
    // temporarily rename the test zip file to the expected resource path on disk.

    // The resourceToString method calls getResourceFile("/ParseBenchmarkData.zip")
    // which returns a File object. We don't have the source for getResourceFile,
    // but it is public static File getResourceFile(String path).

    // So let's invoke getResourceFile("/ParseBenchmarkData.zip") and check what it returns.
    // If it returns a file that does not exist, resourceToString will fail.
    // So we temporarily rename our tempZipFile to the path that getResourceFile expects.

    // Let's invoke getResourceFile to find the expected file path.
    File resourceFile = (File) getResourceFile.invoke(null, "/ParseBenchmarkData.zip");

    // Rename tempZipFile to resourceFile path
    File originalFile = resourceFile.exists() ? resourceFile : null;
    if (originalFile != null) {
      // Rename original file to backup
      File backupFile = new File(resourceFile.getAbsolutePath() + ".bak");
      if (!resourceFile.renameTo(backupFile)) {
        throw new IOException("Failed to rename original resource file");
      }
      // Rename tempZipFile to resourceFile
      if (!tempZipFile.renameTo(resourceFile)) {
        // Restore original file
        backupFile.renameTo(resourceFile);
        throw new IOException("Failed to rename temp zip file to resource file");
      }

      try {
        // Now invoke resourceToString
        Method resourceToString = ParseBenchmark.class.getDeclaredMethod("resourceToString", String.class);
        resourceToString.setAccessible(true);
        String content = (String) resourceToString.invoke(null, "testFile.txt");
        assertEquals("Hello, world!", content);
      } finally {
        // Restore files
        resourceFile.delete();
        backupFile.renameTo(resourceFile);
      }
    } else {
      // Resource file does not exist, so rename tempZipFile to resourceFile path
      if (!tempZipFile.renameTo(resourceFile)) {
        throw new IOException("Failed to rename temp zip file to resource file");
      }
      try {
        Method resourceToString = ParseBenchmark.class.getDeclaredMethod("resourceToString", String.class);
        resourceToString.setAccessible(true);
        String content = (String) resourceToString.invoke(null, "testFile.txt");
        assertEquals("Hello, world!", content);
      } finally {
        resourceFile.delete();
      }
    }
  }

  @Test
  void resourceToString_throwsExceptionForMissingEntry() throws Exception {
    Method resourceToString = ParseBenchmark.class.getDeclaredMethod("resourceToString", String.class);
    resourceToString.setAccessible(true);

    // Similar to above, rename tempZipFile to resourceFile path
    Method getResourceFile = ParseBenchmark.class.getDeclaredMethod("getResourceFile", String.class);
    getResourceFile.setAccessible(true);
    File resourceFile = (File) getResourceFile.invoke(null, "/ParseBenchmarkData.zip");

    if (!tempZipFile.exists()) {
      throw new IllegalStateException("Temp zip file does not exist");
    }

    File originalFile = resourceFile.exists() ? resourceFile : null;
    if (originalFile != null) {
      File backupFile = new File(resourceFile.getAbsolutePath() + ".bak");
      if (!resourceFile.renameTo(backupFile)) {
        throw new IOException("Failed to rename original resource file");
      }
      if (!tempZipFile.renameTo(resourceFile)) {
        backupFile.renameTo(resourceFile);
        throw new IOException("Failed to rename temp zip file to resource file");
      }
      try {
        assertThrows(InvocationTargetException.class, () -> {
          resourceToString.invoke(null, "nonexistent.txt");
        });
      } finally {
        resourceFile.delete();
        backupFile.renameTo(resourceFile);
      }
    } else {
      if (!tempZipFile.renameTo(resourceFile)) {
        throw new IOException("Failed to rename temp zip file to resource file");
      }
      try {
        assertThrows(InvocationTargetException.class, () -> {
          resourceToString.invoke(null, "nonexistent.txt");
        });
      } finally {
        resourceFile.delete();
      }
    }
  }
}
